def extract_relevant_glossary(
    source: str, glossary: dict[str, str]
) -> dict[str, str]:
    source_lower = source.lower()
    return {src: tgt for src, tgt in glossary.items() if src.lower() in source_lower}


def check_glossary_hit_rate(
    translation: str, used_glossary: dict[str, str]
) -> tuple[float, list[str]]:
    translation_lower = translation.lower()
    hits = [tgt for tgt in used_glossary.values() if tgt.lower() in translation_lower]
    misses = [tgt for tgt in used_glossary.values() if tgt.lower() not in translation_lower]
    rate = len(hits) / len(used_glossary) if used_glossary else 1.0
    return rate, misses


GLOSSARY = {
    "machine learning": "apprentissage automatique",
    "neural network": "reseau de neurones",
    "training data": "donnees d'entrainement",
    "overfitting": "surajustement",
    "hyperparameter": "hyperparametre",
}

source = "Tuning hyperparameters prevents overfitting in neural networks."
relevant = extract_relevant_glossary(source, GLOSSARY)
print(relevant)
# {'neural network': 'reseau de neurones', 'overfitting': 'surajustement', 'hyperparameter': 'hyperparametre'}

translation = translate(source, "English", "French", glossary=relevant)
hit_rate, misses = check_glossary_hit_rate(translation, relevant)
if hit_rate < 1.0:
    print(f"Glossary miss: {misses} — consider re-translating or flagging for PE")

from difflib import SequenceMatcher
from dataclasses import dataclass, field

@dataclass
class TMEntry:
    source: str
    translation: str
    lang_pair: str  # e.g. "en-fr"


@dataclass
class TranslationMemory:
    entries: list[TMEntry] = field(default_factory=list)

    def lookup(
        self, source: str, lang_pair: str, threshold: float = 0.95
    ) -> TMEntry | None:
        for entry in self.entries:
            if entry.lang_pair != lang_pair:
                continue
            ratio = SequenceMatcher(None, source, entry.source).ratio()
            if ratio >= threshold:
                return entry
        return None

    def add(self, entry: TMEntry) -> None:
        self.entries.append(entry)


tm = TranslationMemory()

def translate_with_tm(
    source: str,
    src_lang: str,
    tgt_lang: str,
    memory: TranslationMemory,
    glossary: dict[str, str] | None = None,
) -> tuple[str, bool]:
    lang_pair = f"{src_lang[:2].lower()}-{tgt_lang[:2].lower()}"
    match = memory.lookup(source, lang_pair)
    if match:
        return match.translation, True  # TM hit, no API call

    translation = translate(source, src_lang, tgt_lang, glossary)
    return translation, False  # API call made
